try {
    // 1. Captura Segura do Input (Tenta 'query' ou 'args' ou objeto vazio)
    // Isso evita o erro "undefined"
    let inputs = {};
    if (typeof query !== 'undefined') inputs = query;
    else if (typeof args !== 'undefined') inputs = args;

    // Pega o CPF ou string vazia
    const rawCPF = inputs.cpf_number || "";

    // 2. Função de Validação (Sem Regex pesado)
    function validate(str) {
        if (!str || typeof str !== 'string') return false;

        // Limpeza manual para evitar travamento de Regex
        let cpf = "";
        for (let i = 0; i < str.length; i++) {
            if (str[i] >= '0' && str[i] <= '9') cpf += str[i];
            // Trava de segurança: se o usuário mandou um texto gigante, para no 11º dígito
            if (cpf.length > 11) break; 
        }

        if (cpf.length !== 11) return false;

        // Verifica digitos iguais (111.111.111-11)
        let iguais = true;
        for (let i = 1; i < 11; i++) {
            if (cpf[i] !== cpf[0]) iguais = false;
        }
        if (iguais) return false;

        // Cálculo Matemático Puro
        let soma = 0;
        let resto;

        for (let i = 1; i <= 9; i++) 
            soma = soma + parseInt(cpf.substring(i-1, i)) * (11 - i);
        resto = (soma * 10) % 11;

        if ((resto === 10) || (resto === 11))  resto = 0;
        if (resto !== parseInt(cpf.substring(9, 10)) ) return false;

        soma = 0;
        for (let i = 1; i <= 10; i++) 
            soma = soma + parseInt(cpf.substring(i-1, i)) * (12 - i);
        resto = (soma * 10) % 11;

        if ((resto === 10) || (resto === 11))  resto = 0;
        if (resto !== parseInt(cpf.substring(10, 11) ) ) return false;

        return { valid: true, clean: cpf };
    }

    // 3. Execução
    const result = validate(rawCPF);

    // Formatação segura
    let finalFormat = rawCPF;
    if (result && result.valid) {
        const c = result.clean;
        finalFormat = c.substring(0,3) + "." + c.substring(3,6) + "." + c.substring(6,9) + "-" + c.substring(9,11);
    }

    // 4. Retorno (Stringify obrigatório)
    return JSON.stringify({
        "valid": result ? result.valid : false,
        "formatted": finalFormat,
        "message": (result && result.valid) ? "CPF Válido" : "CPF Inválido"
    });

} catch (error) {
    // Se der qualquer erro catastrófico, retorna erro legível em vez de travar
    return JSON.stringify({
        "valid": false,
        "formatted": "",
        "message": "Erro técnico na validação: " + error.message
    });
}
